#!/usr/bin/env python3
import psycopg2
import sys

DB_CONFIG = {
    "host": "172.17.0.1",
    "port": "5432",
    "user": "postgres",
    "password": "password",
    "dbname": "postgres"
}

def main():
    try:
        # Connect to PostgreSQL
        conn = psycopg2.connect(**DB_CONFIG)
        print("Successfully connected to the database")
        conn.close()
    except Exception as e:
        print(f"Error connecting to database: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()
